     1→import { test, expect, type Page } from '@playwright/test';
     2→import pg from 'pg';
     3→import jwt from 'jsonwebtoken';
     4→
     5→const { Pool } = pg;
     6→
     7→const JWT_SECRET = process.env.JWT_SECRET || 'dev-secret-change-me';
     8→const DATABASE_URL = process.env.DATABASE_URL;
     9→
    10→function dbPool(): InstanceType<typeof Pool> {
    11→  if (!DATABASE_URL) throw new Error('DATABASE_URL is not set');
    12→  return new Pool({ connectionString: DATABASE_URL });
    13→}
