    17→test('dev login lands on dashboard', async ({ page, request }) => {
    18→  const res = await request.get('/api/auth/dev-login');
    19→  expect(res.ok()).toBeTruthy();
    20→  const { token } = await res.json();
    21→
    22→  await page.goto('/');
    23→  await page.evaluate((t: string) => localStorage.setItem('token', t), token);
    24→  await page.goto('/');
    25→
    26→  // Auth-guarded route '/' should load dashboard, not redirect to /login
    27→  await expect(page).not.toHaveURL(/\/login/);
    28→  await expect(page.locator('body')).toBeVisible();
    29→});
