    46→// ── Invite accept flow ─────────────────────────────────────────────────────
    47→
    48→test('invited user can accept invitation and join org', async ({ page, request }) => {
    49→  test.skip(!DATABASE_URL, 'DATABASE_URL not configured — skipping invite flow test');
    50→
    51→  const ts = Date.now();
    52→  const userBEmail = `userb${ts}@example.com`;
    53→
    54→  // Step 1: Dev login as user A
    55→  const resA = await request.get('/api/auth/dev-login');
    56→  expect(resA.ok()).toBeTruthy();
    57→  const { token: tokenA } = await resA.json();
    58→
    59→  // Step 2: Create a fresh org as user A
    60→  const orgRes = await request.post('/api/organizations', {
    61→    headers: { Authorization: `Bearer ${tokenA}` },
    62→    data: { name: `Test Org ${ts}`, slug: `testorg${ts}` },
    63→  });
    64→  expect(orgRes.ok()).toBeTruthy();
    65→  const org = await orgRes.json() as { id: string };
    66→
    67→  // Step 3: Invite user B to the org
    68→  const inviteRes = await request.post('/api/invitations', {
    69→    headers: {
    70→      Authorization: `Bearer ${tokenA}`,
    71→      'X-Organization-Id': org.id,
    72→    },
    73→    data: { email: userBEmail, role: 'member' },
    74→  });
    75→  expect(inviteRes.ok()).toBeTruthy();
    76→
    77→  // Step 4: Fetch the invitation token from the database
    78→  const pool = dbPool();
    79→  let inviteToken: string;
    80→  try {
    81→    const result = await pool.query<{ token: string }>(
    82→      'SELECT token FROM invitations WHERE email = $1 ORDER BY created_at DESC LIMIT 1',
    83→      [userBEmail],
    84→    );
    85→    inviteToken = result.rows[0]?.token;
    86→    expect(inviteToken).toBeTruthy();
    87→  } finally {
    88→    await pool.end();
    89→  }
    90→
    91→  // Step 5: Verify GET /api/invitations/:token returns correct details
    92→  const inviteDetails = await request.get(`/api/invitations/${inviteToken}`);
    93→  expect(inviteDetails.ok()).toBeTruthy();
    94→  const details = await inviteDetails.json() as { email: string; role: string };
    95→  expect(details.email).toBe(userBEmail);
    96→  expect(details.role).toBe('member');
    97→
    98→  // Step 6: Register user B (creates user in DB; email hub logs in dev mode)
    99→  const registerRes = await request.post('/api/auth/register', {
   100→    data: { email: userBEmail, name: `User B ${ts}` },
   101→  });
   102→  expect(registerRes.status()).toBe(200);
   103→
   104→  // Step 7: Mint a JWT for user B via DB lookup (avoids needing a real PIN email)
   105→  const pool2 = dbPool();
   106→  let userBToken: string;
   107→  try {
   108→    const userResult = await pool2.query<{ id: string; email: string }>(
   109→      'SELECT id, email FROM users WHERE email = $1',
   110→      [userBEmail],
   111→    );
   112→    const userB = userResult.rows[0];
   113→    expect(userB).toBeTruthy();
   114→    userBToken = jwt.sign(
   115→      { userId: userB.id, email: userB.email },
   116→      JWT_SECRET,
   117→      { expiresIn: '1h' },
   118→    ) as string;
   119→  } finally {
   120→    await pool2.end();
   121→  }
   122→
   123→  // Step 8: Navigate to the invite page as user B and accept
   124→  await page.goto('/');
   125→  await page.evaluate((t: string) => localStorage.setItem('token', t), userBToken);
   126→  await page.goto(`/invite/${inviteToken}`);
   127→
   128→  await expect(page.locator("text=You're invited!")).toBeVisible({ timeout: 10_000 });
   129→  await page.click('button:has-text("Accept invitation")');
   130→
   131→  // Should redirect to dashboard after accepting
   132→  await expect(page).toHaveURL('/', { timeout: 10_000 });
   133→
   134→  // Step 9: Confirm user B is now a member of the org via API
   135→  const orgsRes = await request.get('/api/organizations', {
   136→    headers: { Authorization: `Bearer ${userBToken}` },
   137→  });
   138→  expect(orgsRes.ok()).toBeTruthy();
   139→  const orgs = await orgsRes.json() as Array<{ id: string }>;
   140→  const joined = orgs.find((o) => o.id === org.id);
   141→  expect(joined).toBeTruthy();
   142→});
