   144→// ── Passkey flows (WebAuthn) ─────────────────────────────────────────────────
   145→
   146→/**
   147→ * Set up a CDP WebAuthn virtual authenticator on the given page.
   148→ * Returns a cleanup function that detaches the CDP session.
   149→ *
   150→ * Requires Chromium — virtual authenticators rely on the Chrome DevTools Protocol.
   151→ */
   152→async function setupVirtualAuthenticator(page: Page): Promise<() => Promise<void>> {
   153→  const client = await page.context().newCDPSession(page);
   154→  await client.send('WebAuthn.enable');
   155→  await client.send('WebAuthn.addVirtualAuthenticator', {
   156→    options: {
   157→      protocol: 'ctap2',
   158→      transport: 'internal',
   159→      hasResidentKey: true,
   160→      hasUserVerification: true,
   161→      isUserVerified: true,
   162→    },
   163→  });
   164→  return () => client.detach();
   165→}
   166→
   167→/**
   168→ * Invoke navigator.credentials.create() in the browser using the given options
   169→ * (binary fields are base64url strings as returned by @simplewebauthn/server).
   170→ * Returns the registration credential serialised to base64url JSON.
   171→ */
   172→async function performRegistrationCeremony(
   173→  page: Page,
   174→  options: Record<string, unknown>,
   175→): Promise<Record<string, unknown>> {
   176→  return page.evaluate(async (opts) => {
   177→    function b64urlToBuffer(b64url: string): ArrayBuffer {
   178→      const base64 = b64url.replace(/-/g, '+').replace(/_/g, '/');
   179→      const padded = base64.padEnd(base64.length + (4 - (base64.length % 4)) % 4, '=');
   180→      const binary = atob(padded);
   181→      const bytes = new Uint8Array(binary.length);
   182→      for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
   183→      return bytes.buffer;
   184→    }
   185→    function bufferToB64url(buf: ArrayBuffer | Uint8Array): string {
   186→      const bytes = buf instanceof Uint8Array ? buf : new Uint8Array(buf);
   187→      let binary = '';
   188→      for (const b of bytes) binary += String.fromCharCode(b);
   189→      return btoa(binary).replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
   190→    }
   191→
   192→    // eslint-disable-next-line @typescript-eslint/no-explicit-any
   193→    const o = opts as any;
   194→    // eslint-disable-next-line @typescript-eslint/no-explicit-any
   195→    const cred: any = await (navigator as any).credentials.create({
   196→      publicKey: {
   197→        ...o,
   198→        challenge: b64urlToBuffer(o.challenge),
   199→        user: { ...o.user, id: b64urlToBuffer(o.user.id) },
   200→        excludeCredentials: (o.excludeCredentials ?? []).map((c: any) => ({
   201→          ...c,
   202→          id: b64urlToBuffer(c.id),
   203→        })),
   204→      },
   205→    });
   206→
   207→    const resp = cred.response;
   208→    return {
   209→      id: cred.id,
   210→      rawId: bufferToB64url(cred.rawId),
   211→      type: cred.type,
   212→      response: {
   213→        clientDataJSON: bufferToB64url(resp.clientDataJSON),
   214→        attestationObject: bufferToB64url(resp.attestationObject),
   215→        transports: resp.getTransports?.() ?? [],
   216→      },
   217→      clientExtensionResults: {},
   218→      authenticatorAttachment: cred.authenticatorAttachment ?? 'platform',
   219→    };
   220→  }, options);
   221→}
   222→
   223→/**
   224→ * Invoke navigator.credentials.get() in the browser using the given options
   225→ * (binary fields are base64url strings as returned by @simplewebauthn/server).
   226→ * Returns the authentication assertion serialised to base64url JSON.
   227→ */
   228→async function performAuthenticationCeremony(
   229→  page: Page,
   230→  options: Record<string, unknown>,
   231→): Promise<Record<string, unknown>> {
   232→  return page.evaluate(async (opts) => {
   233→    function b64urlToBuffer(b64url: string): ArrayBuffer {
   234→      const base64 = b64url.replace(/-/g, '+').replace(/_/g, '/');
   235→      const padded = base64.padEnd(base64.length + (4 - (base64.length % 4)) % 4, '=');
   236→      const binary = atob(padded);
   237→      const bytes = new Uint8Array(binary.length);
   238→      for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
   239→      return bytes.buffer;
   240→    }
   241→    function bufferToB64url(buf: ArrayBuffer | Uint8Array): string {
   242→      const bytes = buf instanceof Uint8Array ? buf : new Uint8Array(buf);
   243→      let binary = '';
   244→      for (const b of bytes) binary += String.fromCharCode(b);
   245→      return btoa(binary).replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
   246→    }
   247→
   248→    // eslint-disable-next-line @typescript-eslint/no-explicit-any
   249→    const o = opts as any;
   250→    // eslint-disable-next-line @typescript-eslint/no-explicit-any
   251→    const cred: any = await (navigator as any).credentials.get({
   252→      publicKey: {
   253→        ...o,
   254→        challenge: b64urlToBuffer(o.challenge),
   255→        allowCredentials: (o.allowCredentials ?? []).map((c: any) => ({
   256→          ...c,
   257→          id: b64urlToBuffer(c.id),
   258→        })),
   259→      },
   260→    });
   261→
   262→    const resp = cred.response;
   263→    return {
   264→      id: cred.id,
   265→      rawId: bufferToB64url(cred.rawId),
   266→      type: cred.type,
   267→      response: {
   268→        clientDataJSON: bufferToB64url(resp.clientDataJSON),
   269→        authenticatorData: bufferToB64url(resp.authenticatorData),
   270→        signature: bufferToB64url(resp.signature),
   271→        userHandle: resp.userHandle != null ? bufferToB64url(resp.userHandle) : null,
   272→      },
   273→      clientExtensionResults: {},
   274→      authenticatorAttachment: cred.authenticatorAttachment ?? 'platform',
   275→    };
   276→  }, options);
   277→}
