   279→test('passkey registration: register, list, and delete a passkey device', async ({ page }) => {
   280→  test.skip(!DATABASE_URL, 'DATABASE_URL not configured — skipping passkey registration test');
   281→
   282→  // Authenticate via dev-login (sets httpOnly JWT cookie in the page's browser context)
   283→  const loginRes = await page.request.get('/api/auth/dev-login');
   284→  expect(loginRes.ok()).toBeTruthy();
   285→
   286→  // Navigate to the frontend so WebAuthn uses the correct origin (http://localhost:5173)
   287→  await page.goto('/');
   288→
   289→  const teardown = await setupVirtualAuthenticator(page);
   290→
   291→  try {
   292→    // Clean up any passkeys left over from previous test runs
   293→    const existing = await page.request.get('/api/auth/passkeys');
   294→    for (const pk of await existing.json() as Array<{ id: string }>) {
   295→      await page.request.delete(`/api/auth/passkeys/${pk.id}`);
   296→    }
   297→
   298→    // Begin registration — server generates a challenge and registration options
   299→    const beginRes = await page.request.post('/api/auth/passkey/register/begin');
   300→    expect(beginRes.ok()).toBeTruthy();
   301→    const regOptions = await beginRes.json() as Record<string, unknown>;
   302→    expect(typeof regOptions['challenge']).toBe('string');
   303→
   304→    // Perform the WebAuthn ceremony in the browser using the CDP virtual authenticator
   305→    const credential = await performRegistrationCeremony(page, regOptions);
   306→    expect(credential['id']).toBeTruthy();
   307→
   308→    // Complete registration — server verifies the credential and stores it
   309→    const completeRes = await page.request.post('/api/auth/passkey/register/complete', {
   310→      data: { response: credential, deviceName: 'Test Key' },
   311→    });
   312→    expect(completeRes.ok()).toBeTruthy();
   313→    const { success, credentialId } = await completeRes.json() as { success: boolean; credentialId: string };
   314→    expect(success).toBe(true);
   315→    expect(credentialId).toBeTruthy();
   316→
   317→    // List passkeys — should contain the newly registered device
   318→    const listRes = await page.request.get('/api/auth/passkeys');
   319→    expect(listRes.ok()).toBeTruthy();
   320→    const passkeys = await listRes.json() as Array<{ id: string; deviceName: string | null; createdAt: string }>;
   321→    expect(passkeys).toHaveLength(1);
   322→    expect(passkeys[0]?.deviceName).toBe('Test Key');
   323→    expect(passkeys[0]?.createdAt).toBeTruthy();
   324→
   325→    // Delete the passkey
   326→    const deleteRes = await page.request.delete(`/api/auth/passkeys/${passkeys[0]?.id}`);
   327→    expect(deleteRes.ok()).toBeTruthy();
   328→    const { success: deleted } = await deleteRes.json() as { success: boolean };
   329→    expect(deleted).toBe(true);
   330→
   331→    // Verify the passkey no longer appears in the list
   332→    const listAfterDelete = await page.request.get('/api/auth/passkeys');
   333→    expect(listAfterDelete.ok()).toBeTruthy();
   334→    expect(await listAfterDelete.json() as Array<unknown>).toHaveLength(0);
   335→  } finally {
   336→    await teardown();
   337→  }
   338→});
