   340→test('passkey login: authenticate via passkey after registering one', async ({ page }) => {
   341→  test.skip(!DATABASE_URL, 'DATABASE_URL not configured — skipping passkey login test');
   342→
   343→  // Authenticate via dev-login (sets httpOnly JWT cookie in the page's browser context)
   344→  const loginRes = await page.request.get('/api/auth/dev-login');
   345→  expect(loginRes.ok()).toBeTruthy();
   346→  const { user: devUser } = await loginRes.json() as { user: { id: string; email: string } };
   347→
   348→  // Navigate to the frontend so WebAuthn uses the correct origin (http://localhost:5173)
   349→  await page.goto('/');
   350→
   351→  const teardown = await setupVirtualAuthenticator(page);
   352→
   353→  try {
   354→    // Clean up any passkeys left over from previous test runs
   355→    const existing = await page.request.get('/api/auth/passkeys');
   356→    for (const pk of await existing.json() as Array<{ id: string }>) {
   357→      await page.request.delete(`/api/auth/passkeys/${pk.id}`);
   358→    }
   359→
   360→    // Register a passkey for the dev user
   361→    const beginRegRes = await page.request.post('/api/auth/passkey/register/begin');
   362→    expect(beginRegRes.ok()).toBeTruthy();
   363→    const regCred = await performRegistrationCeremony(page, await beginRegRes.json() as Record<string, unknown>);
   364→    const completeRegRes = await page.request.post('/api/auth/passkey/register/complete', {
   365→      data: { response: regCred },
   366→    });
   367→    expect(completeRegRes.ok()).toBeTruthy();
   368→
   369→    // Logout so we can test passkey login from an unauthenticated state
   370→    await page.request.post('/api/auth/logout');
   371→
   372→    // Begin passkey authentication — server generates a challenge
   373→    const beginLoginRes = await page.request.post('/api/auth/passkey/login/begin', {
   374→      data: { email: devUser.email },
   375→    });
   376→    expect(beginLoginRes.ok()).toBeTruthy();
   377→    const loginOptions = await beginLoginRes.json() as Record<string, unknown>;
   378→    expect(typeof loginOptions['challenge']).toBe('string');
   379→
   380→    // Perform the WebAuthn authentication ceremony in the browser
   381→    const assertion = await performAuthenticationCeremony(page, loginOptions);
   382→    expect(assertion['id']).toBeTruthy();
   383→
   384→    // Complete passkey login — server verifies the assertion and sets a JWT cookie
   385→    const completeLoginRes = await page.request.post('/api/auth/passkey/login/complete', {
   386→      data: { email: devUser.email, response: assertion },
   387→    });
   388→    expect(completeLoginRes.ok()).toBeTruthy();
   389→    const loginBody = await completeLoginRes.json() as { user: { id: string; email: string } };
   390→    expect(loginBody.user).toBeDefined();
   391→    expect(loginBody.user.email).toBe(devUser.email);
   392→
   393→    // Verify the JWT cookie was set by making an authenticated request
   394→    const meRes = await page.request.get('/api/users/me');
   395→    expect(meRes.ok()).toBeTruthy();
   396→    const me = await meRes.json() as { id: string; email: string };
   397→    expect(me.email).toBe(devUser.email);
   398→
   399→    // Clean up: delete the registered passkey
   400→    const finalPasskeys = await page.request.get('/api/auth/passkeys');
   401→    for (const pk of await finalPasskeys.json() as Array<{ id: string }>) {
   402→      await page.request.delete(`/api/auth/passkeys/${pk.id}`);
   403→    }
   404→  } finally {
   405→    await teardown();
   406→  }
   407→});
