   467→test('passkey login/complete: invalid credential returns 401', async ({ page, request }) => {
   468→  test.skip(!DATABASE_URL, 'DATABASE_URL not configured — skipping passkey invalid-credential test');
   469→
   470→  // Ensure dev user has a passkey registered so login/begin succeeds and creates a challenge
   471→  const loginRes = await page.request.get('/api/auth/dev-login');
   472→  expect(loginRes.ok()).toBeTruthy();
   473→  const { user: devUser } = await loginRes.json() as { user: { email: string } };
   474→
   475→  await page.goto('/');
   476→  const teardown = await setupVirtualAuthenticator(page);
   477→
   478→  try {
   479→    // Clean up and register a fresh passkey so login/begin has credentials to offer
   480→    const existing = await page.request.get('/api/auth/passkeys');
   481→    for (const pk of await existing.json() as Array<{ id: string }>) {
   482→      await page.request.delete(`/api/auth/passkeys/${pk.id}`);
   483→    }
   484→    const beginRegRes = await page.request.post('/api/auth/passkey/register/begin');
   485→    expect(beginRegRes.ok()).toBeTruthy();
   486→    const regCred = await performRegistrationCeremony(page, await beginRegRes.json() as Record<string, unknown>);
   487→    await page.request.post('/api/auth/passkey/register/complete', { data: { response: regCred } });
   488→
   489→    await page.request.post('/api/auth/logout');
   490→
   491→    // Begin login to establish a valid server-side challenge for the dev user's email
   492→    const beginLoginRes = await request.post('/api/auth/passkey/login/begin', {
   493→      data: { email: devUser.email },
   494→    });
   495→    expect(beginLoginRes.ok()).toBeTruthy();
   496→
   497→    // Submit a tampered credential response — the credential ID does not exist for this user
